type CenterFrom int64 //gd:SpringBoneSimulator3D.CenterFrom

const (
	// The world origin is defined as center.
	CenterFromWorldOrigin CenterFrom = 0
	// The [Node3D] specified by [SetCenterNode] is defined as center.
	//
	// If [Node3D] is not found, the parent [Skeleton3D] is treated as center.
	//
	// [Node3D]: https://pkg.go.dev/graphics.gd/classdb/Node3D
	// [SetCenterNode]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetCenterNode
	// [Skeleton3D]: https://pkg.go.dev/graphics.gd/classdb/Skeleton3D
	CenterFromNode CenterFrom = 1
	// The bone pose origin of the parent [Skeleton3D] specified by [SetCenterBone] is defined as center.
	//
	// If [Node3D] is not found, the parent [Skeleton3D] is treated as center.
	//
	// [Node3D]: https://pkg.go.dev/graphics.gd/classdb/Node3D
	// [SetCenterBone]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetCenterBone
	// [Skeleton3D]: https://pkg.go.dev/graphics.gd/classdb/Skeleton3D
	CenterFromBone CenterFrom = 2
)
